      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const errors = require('../../lib/errors');

let projects = {};

const addTaskToProject = (projectId, title) => {
  if (!projects[projectId]) {
    return null; // Project not found
  }

  const project = projects[projectId];
  const newTask = { id: randomUUID(), title, status: 'todo' };
  project.tasks.push(newTask);
  return newTask;
};

const getTasksByProjectId = (projectId) => {
  if (!projects[projectId]) {
    return null; // Project not found
  }
  return projects[projectId].tasks;
};

const updateTaskStatus = (projectId, taskId, status) => {
  if (!projects[projectId]) {
    return null; // Project not found
  }

  const project = projects[projectId];
  const task = project.tasks.find(task => task.id === taskId);

  if (!task) {
    return null; // Task not found
  }

  if (status !== 'todo' && status !== 'done') {
    return null; // Invalid status
  }

  task.status = status;
  return task;
};

module.exports = {
  addTaskToProject,
  getTasksByProjectId,
  updateTaskStatus,
};
